// 封装一个通用的处理函数
function normalizeDate(inputDate) {
  if (!inputDate) return null;

  // 核心判断逻辑：
  // 检查入参是否为“纯数字”格式（即 Excel 序列号）
  // 正则含义：开头到结尾都是数字，允许包含小数点
  const isExcelFormat = /^\d+(\.\d+)?$/.test(String(inputDate));

  if (isExcelFormat) {
    // === 情况 A: Excel 格式 (例如: 45626) ===
    const excelEpoch = new Date(Date.UTC(1899, 11, 30));
    // 使用 parseFloat 以便保留 Excel 中的时间部分（如果有小数）
    const days = parseFloat(inputDate); 
    const jsDate = new Date(excelEpoch.getTime() + days * 86400000);
    return jsDate.toISOString().split('.')[0];
  } else {
    // === 情况 B: 标准字符串格式 (例如: "2025-11-30 11:46:54") ===
    // 尝试直接解析
    const jsDate = new Date(inputDate);

    // 如果解析结果是有效日期
    if (!isNaN(jsDate.getTime())) {
      // 统一输出为 ISO 格式，保持与 Excel 处理逻辑一致的输出风格
      return jsDate.toISOString().split('.')[0];
    }

    // 如果都解析不了，返回原值
    return inputDate;
  }
}

const transformedData = $input.all().map(item => {
  // 你的入参结构看起来是 { json: { SN:..., Date:... } } 或者直接是对象数组
  // 根据你提供的代码上下文，经常是 { json: ... } 结构
  const newItem = item.json ? { ...item.json } : { ...item }; // 兼容带 json 包装或不带的情况

  newItem.Date = normalizeDate(newItem.Date);

  // 保持原有返回结构
  return { ...item, json: newItem };
});

return transformedData;

function processDate(inputDate) {
  if (!inputDate) return null;

  const dateStr = String(inputDate);

  // 核心判断：正则检查是否“纯数字”（允许带小数点），例如 45230 或 45230.5
  // 如果是纯数字，说明是 Excel 格式
  const isExcelFormat = /^\d+(\.\d+)?$/.test(dateStr);

  let jsDate;

  if (isExcelFormat) {
    // === 处理 Excel 数字格式 ===
    const excelEpoch = new Date(Date.UTC(1899, 11, 30));
    const days = parseFloat(inputDate); // 建议用 parseFloat 以保留时间精度
    jsDate = new Date(excelEpoch.getTime() + days * 86400000);
  } else {
    // === 处理 "2025-10-10" 或 "2025-11-30..." 字符串格式 ===
    // 直接利用 JS 原生能力解析
    jsDate = new Date(inputDate);
  }

  // 检查是否转换成功
  if (isNaN(jsDate.getTime())) {
    return inputDate; // 如果解析失败，返回原值
  }

  // 统一输出 ISO 格式 (YYYY-MM-DDTHH:mm:ss)
  return jsDate.toISOString().split('.')[0];
}

const transformedData = $input.all().map(item => {
  const newItem = {...item.json}; // 复制对象
  newItem.Date = processDate(newItem.Date); // 转换日期
  return { ...item, json: newItem };
});

return transformedData;

const input = $input.all();

const result = input
  .filter(item => item.json.sn !== "''") // 过滤掉 sn 为 "''" 的项
  .map(item => item.json.sn)
  .join(',');

return { snlist: result };

const input = $input.all();

const result = input.map(item => item.json.Id).join(',');

return { Idlist: result };

let res = [];
for (const item of $input.all()) {
  const itemContent = item.json;
  if (!itemContent) continue; // 如果 itemContent 为空则跳过

  // 遍历 itemContent 的所有项
  for (const key in itemContent) {
    if (!itemContent.hasOwnProperty(key)) continue;

    const cur = itemContent[key];
    let hasError = false;

    if (key === 'errdefective' && Array.isArray(cur)) {
      hasError = true;
      const temp = cur.map(defectiveItem => ({
        SN: defectiveItem['retroid'],
        Reason: '该设备已有不良记录',
      }));
      res = res.concat(temp);
    } else if (key === 'SuccessItem' && Array.isArray(cur)) {
      hasError = true;
      const temp = cur.map(successItem => ({
        SN: successItem['retroid'],
        Reason: '该设备已成功上传',
      }));
      res = res.concat(temp);
    } else if (key === 'errActiveItem' && Array.isArray(cur)) {
      hasError = true;
      const temp = cur.map(errActive => ({
        SN: errActive['SN'],
        Reason: '该设备未激活',
      }));
      res = res.concat(temp);
    }

    if (!hasError) {
      res.push({ SN: null, Reason: '上传失败' });
    }
  }
}

return {
  result: res
};
